mapper.select:
SELECT a.ta_id, a.course_id, c.course_name, a.member_id, a.member_name, a.attend_date, a.status FROM erp_training_attendance a LEFT JOIN erp_course c ON a.course_id = c.course_id
AND a.member_name LIKE '%' || #{keyword} || '%'
ORDER BY a.attend_date DESC LIMIT #{limit} OFFSET #{offset}
